import asyncio
import json
import random
import socket
import struct
import time
from dataclasses import dataclass, asdict, field
from typing import Dict, List, Tuple, Any


@dataclass
class Player:
    id: int
    name: str
    score: int
    ping: int
    team: str
    connected_at: float

    def to_dict(self) -> Dict[str, Any]:
        d = asdict(self)
        d["session_seconds"] = int(time.time() - self.connected_at)
        return d


@dataclass
class GameState:
    server_name: str
    map_name: str
    mode: str
    max_players: int
    round_time_remaining: int
    tick_rate: int
    version: str
    motd: str
    password_protected: bool = False
    friendly_fire: bool = False
    bots: int = 0
    spectators: int = 0
    tags: List[str] = field(default_factory=lambda: ["public", "browser", "udp"])

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)


class QueryProtocol(asyncio.DatagramProtocol):
    def __init__(self, server: "GameServer"):
        self.server = server
        self.transport = None

    def connection_made(self, transport):
        self.transport = transport
        self.server.transport = transport
        sock = transport.get_extra_info("socket")
        if sock is not None:
            try:
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1 << 20)
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1 << 20)
            except OSError:
                pass

    def datagram_received(self, data: bytes, addr: Tuple[str, int]):
        self.server.handle_query(data, addr)

    def error_received(self, exc):
        pass

    def connection_lost(self, exc):
        self.server.transport = None


class GameServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 27015):
        self.host = host
        self.port = port
        self.transport = None
        self.start_time = time.time()
        self.state = GameState(
            server_name="Example Arena Server",
            map_name="arena_harbor",
            mode="Team Deathmatch",
            max_players=128,
            round_time_remaining=900,
            tick_rate=64,
            version="1.0.0",
            motd="Welcome to Example Arena!",
        )
        self.players: List[Player] = self._generate_players(96)
        self.challenge_tokens: Dict[Tuple[str, int], int] = {}

    def _generate_players(self, count: int) -> List[Player]:
        first = [
            "Alex", "Blake", "Casey", "Dakota", "Evan", "Flynn", "Gray", "Harper",
            "Indy", "Jules", "Kai", "Logan", "Morgan", "Nico", "Oak", "Parker",
            "Quinn", "Reese", "Sawyer", "Toby", "Vale", "Winter", "Xen", "Yael", "Zane"
        ]
        suffixes = ["", "_tv", "_pro", "_x", "_77", "_gg", "_bot", "_live"]
        teams = ["red", "blue"]
        players = []
        now = time.time()
        for i in range(count):
            name = random.choice(first) + random.choice(suffixes) + str(i)
            players.append(
                Player(
                    id=i + 1,
                    name=name,
                    score=random.randint(0, 250),
                    ping=random.randint(15, 180),
                    team=random.choice(teams),
                    connected_at=now - random.randint(30, 7200),
                )
            )
        return players

    def _uptime(self) -> int:
        return int(time.time() - self.start_time)

    def _player_count(self) -> int:
        return len(self.players)

    def _build_status_payload(self) -> Dict[str, Any]:
        return {
            "type": "status",
            "time": int(time.time()),
            "uptime": self._uptime(),
            "server": {
                **self.state.to_dict(),
                "current_players": self._player_count(),
            },
            "game_state": {
                "round_time_remaining": self.state.round_time_remaining,
                "map_name": self.state.map_name,
                "mode": self.state.mode,
                "scores": {
                    "red": sum(p.score for p in self.players if p.team == "red"),
                    "blue": sum(p.score for p in self.players if p.team == "blue"),
                },
            },
            "players": [p.to_dict() for p in self.players],
        }

    def _build_info_payload(self) -> Dict[str, Any]:
        return {
            "type": "info",
            "server_name": self.state.server_name,
            "map_name": self.state.map_name,
            "mode": self.state.mode,
            "players": self._player_count(),
            "max_players": self.state.max_players,
            "bots": self.state.bots,
            "version": self.state.version,
            "password_protected": self.state.password_protected,
        }

    def _encode_packet(self, payload: Dict[str, Any]) -> bytes:
        body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        header = b"GQRY" + struct.pack("!I", len(body))
        return header + body

    def _send_packet(self, addr: Tuple[str, int], payload: Dict[str, Any]):
        if self.transport is None:
            return
        packet = self._encode_packet(payload)
        self.transport.sendto(packet, addr)

    def handle_query(self, data: bytes, addr: Tuple[str, int]):
        if not data:
            return

        try:
            text = data.decode("utf-8", errors="ignore").strip().lower()
        except Exception:
            return

        if text in ("status", "getstatus", "fullstatus", "browser_status"):
            self._send_packet(addr, self._build_status_payload())
        elif text in ("info", "getinfo", "ping"):
            self._send_packet(addr, self._build_info_payload())
        elif text == "players":
            self._send_packet(addr, {
                "type": "players",
                "count": self._player_count(),
                "players": [p.to_dict() for p in self.players],
            })
        else:
            self._send_packet(addr, {
                "type": "error",
                "error": "unknown_query",
                "supported": ["status", "info", "players"],
            })

    async def simulate_game(self):
        while True:
            await asyncio.sleep(1)
            if self.state.round_time_remaining > 0:
                self.state.round_time_remaining -= 1
            else:
                self.state.round_time_remaining = 900
                self.state.map_name = random.choice([
                    "arena_harbor",
                    "arena_foundry",
                    "arena_outpost",
                    "arena_citadel",
                ])
            for p in self.players:
                if random.random() < 0.25:
                    p.score += random.randint(0, 3)
                if random.random() < 0.5:
                    p.ping = max(5, min(250, p.ping + random.randint(-5, 5)))


async def main():
    server = GameServer()
    loop = asyncio.get_running_loop()
    await loop.create_datagram_endpoint(
        lambda: QueryProtocol(server),
        local_addr=(server.host, server.port),
        family=socket.AF_INET,
    )
    asyncio.create_task(server.simulate_game())
    print(f"UDP game query server listening on {server.host}:{server.port}")
    while True:
        await asyncio.sleep(3600)


if __name__ == "__main__":
    asyncio.run(main())